#!/usr/bin/env python3
# Piece 1a — dream-os — the binder ledger + Kriya's hands + Kriya's soul.
#
# Drops, beside the existing vendor structure (nothing wired into the live engine
# yet — that's 1b; nothing in the old ledger dropped — that's 1c):
#   db/migrations/0068_binders.sql   — binders + binder_events (vendor-keyed)
#   src/agent/kriyaPrimitives.js     — write hands (money/date/client/note/.../edit)
#   src/agent/kriyaRead.js           — read hands (find/tally/history)
#   src/agent/kriyaSoul.js           — Kriya's soul (pre-/desk Donna, ported)
#
# Pure additive. The migration is NOT auto-applied — you run 0068 in Supabase.
# Idempotent: overwrites the four generated files; never touches anything else.

import base64, os, sys

ROOT = os.getcwd()

FILE_ORDER = [
    "db/migrations/0068_binders.sql",
    "src/agent/kriyaPrimitives.js",
    "src/agent/kriyaRead.js",
    "src/agent/kriyaSoul.js",
]

def expect_root():
    if not (os.path.isdir(os.path.join(ROOT, "src", "agent")) and os.path.isdir(os.path.join(ROOT, "db", "migrations"))):
        print("ERROR: run from dream-os repo root (src/agent + db/migrations expected). Aborting.")
        sys.exit(1)

def write(relpath, b64):
    full = os.path.join(ROOT, relpath)
    os.makedirs(os.path.dirname(full), exist_ok=True)
    with open(full, "wb") as f:
        f.write(base64.b64decode(b64))
    print(f"OK: wrote {relpath}")

def main():
    expect_root()
    for rel in FILE_ORDER:
        write(rel, PAYLOADS[rel])
    print("\nPiece 1a written (additive — nothing wired, nothing dropped).")
    print("NEXT: apply db/migrations/0068_binders.sql in Supabase (creates binders + binder_events).")
    print("Then 1b wires Kriya into Myra's loop on the vendor chat.")

# base64 payloads injected below
PAYLOADS = {
    'db/migrations/0068_binders.sql': '',
    'src/agent/kriyaPrimitives.js': '',
    'src/agent/kriyaRead.js': '',
    'src/agent/kriyaSoul.js': '',
}

if __name__ == "__main__":
    main()
